package main

import (
	"sort"
	"strconv"
	"strings"
)

func solve(input string) string {
	lines := strings.Split(strings.TrimSpace(input), "\n")
	workerCount, _ := strconv.Atoi(strings.Split(lines[0], "=")[1])
	nums := lines[1:]
	_ = workerCount
	jobs := make(chan int, len(nums))
	results := make(chan int, len(nums))
	// TODO: launch workerCount goroutines, each reads from jobs and sends square to results
	// TODO: send all numbers to jobs channel, close it
	// TODO: collect results and sort them
	close(jobs)
	var squares []int
	_ = squares
	sort.Ints(squares)
	var out []string
	for _, v := range squares {
		out = append(out, strconv.Itoa(v))
	}
	return strings.Join(out, "\n")
}
